"""
Cronos - Ícone embutido como base64.
Gerado automaticamente — cronos.ico e cronos.png para tray.
"""
import base64, tempfile
from pathlib import Path

_ICO_B64 = ""
_PNG_B64 = ""

_cache = {}

def get_icon_path(fmt="png") -> str:
    """Retorna caminho temporário para o ícone (fmt='png'|'ico')."""
    if fmt in _cache:
        return _cache[fmt]
    data = base64.b64decode(_ICO_B64 if fmt == "ico" else _PNG_B64)
    ext = ".ico" if fmt == "ico" else ".png"
    tmp = Path(tempfile.gettempdir()) / f"cronos_icon{ext}"
    tmp.write_bytes(data)
    _cache[fmt] = str(tmp)
    return _cache[fmt]
